package com.example.billing.messaging;

import io.micronaut.configuration.kafka.annotation.KafkaClient;
import io.micronaut.configuration.kafka.annotation.KafkaKey;
import io.micronaut.configuration.kafka.annotation.KafkaListener;
import io.micronaut.configuration.kafka.annotation.Topic;

@KafkaClient
interface OrderEventsClient {
    @Topic("orders.events.v1")
    void send(@KafkaKey String orderId, OrderCreatedEvent event);
}

@KafkaListener(groupId = "billing-service-v1")
class BillingListener {
    @Topic("orders.events.v1")
    void receive(@KafkaKey String orderId, OrderCreatedEvent event) {
        // delegate to app service
        // billingService.process(orderId, event);
    }
}

