        // Bad: untyped payload + no schema contract, missing groupId
    }
}

good-example.code-block:
package com.example.billing.messaging;

import io.micronaut.configuration.kafka.annotation.KafkaListener;
import io.micronaut.configuration.kafka.annotation.Topic;
import io.micronaut.configuration.kafka.exceptions.KafkaListenerExceptionHandlerValue;

@KafkaListener(
    groupId = "billing-service-v1",
    errorStrategy = KafkaListenerExceptionHandlerValue.RETRY_ON_ERROR
)
class BillingListener {
    @Topic("orders.events.v1")
    void receive(OrderCreatedEvent event) {
        // throw to trigger retry policy; publish unrecoverable messages to DLT
        // if processing fails, the framework will retry based on configuration
    }
}

bad-example.code-block:
package com.example.billing.messaging;

import io.micronaut.configuration.kafka.annotation.KafkaListener;
import io.micronaut.configuration.kafka.annotation.Topic;

@KafkaListener(groupId = "billing-service-v1")
class BadBillingListener {
    @Topic("orders.events.v1")
    void receive(OrderCreatedEvent event) {
        try { 
            // process(event); 
        } catch (Exception ignored) {
            // Bad: swallowing exception acknowledges poison messages
        }
    }
}

